最后还需要在 Make/files 中添加下列语句，才能编译出来。
COMPOSITIONINJECTION=submodels/Reacting/InjectionModel/compositionData$(COMPOSITIONINJECTION)/compositionData.C$(COMPOSITIONINJECTION)/compositionDataIO.C$(COMPOSITIONINJECTION)/compositionDataIOList.C



使用方法也很简单，在对应的XXXinjection.H文件中，定义变量injectors_ 为例子
//- List of injectorscompositionDataIOList injectors_;

在XXXinjection.C中 添加
//Constructors处  compositionFile_(this-&gt;coeffDict().lookup(&quot;compositionFile&quot;)),  injectors_(      IOobject(          compositionFile_,          owner.db().time().constant(),          owner.db(),          IOobject::MUST_READ,          IOobject::NO_WRITE))      // 第二部分  compositionFile_(im.compositionFile_),  injectors_(im.injectors_)    



最后在setProperties 方程中添加，下面的语句只会读取文件中的第一行设置。
  // set particle densityparcel.rho() = injectors_[0].rho();// set particle temperatureparcel.T() = injectors_[0].T();// // set particle specific heat capacityparcel.Cp() = injectors_[0].Cp();    // set particle component mass fractionsparcel.Y() = injectors_[0].Y();// set particle gaseous component mass fractionsparcel.YGas() = injectors_[0].YGas();// set particle liquid component mass fractionsparcel.YLiquid() = injectors_[0].YLiquid();// set particle solid component mass fractionsparcel.YSolid() = injectors_[0].YSolid();





