incompressible::turbulenceModel 是 IncompressibleTurbulenceModel&lt;transportModel&gt; 的别名。这里调用的是 IncompressibleTurbulenceModel 类的 New 函数。
template&lt;class TransportModel&gt;Foam::autoPtr&lt;Foam::IncompressibleTurbulenceModel&lt;TransportModel&gt; &gt;Foam::IncompressibleTurbulenceModel&lt;TransportModel&gt;::New(    const volVectorField&amp; U,    const surfaceScalarField&amp; phi,    const TransportModel&amp; transport,    const word&amp; propertiesName)&#123;    return autoPtr&lt;IncompressibleTurbulenceModel&gt;    (        static_cast&lt;IncompressibleTurbulenceModel*&gt;(        TurbulenceModel        &lt;            geometricOneField,            geometricOneField,            incompressibleTurbulenceModel,            TransportModel        &gt;::New        (            geometricOneField(),            geometricOneField(),            U,            phi,            phi,            transport,            propertiesName        ).ptr())    );



返回的是 TurbulenceModel 类的 New 函数。
template&lt;    class Alpha,    class Rho,    class BasicTurbulenceModel,    class TransportModel&gt;Foam::autoPtr&lt;    Foam::TurbulenceModel&lt;Alpha, Rho, BasicTurbulenceModel, TransportModel&gt;&gt;Foam::TurbulenceModel&lt;Alpha, Rho, BasicTurbulenceModel, TransportModel&gt;::New(    const alphaField&amp; alpha,    const rhoField&amp; rho,    const volVectorField&amp; U,    const surfaceScalarField&amp; alphaRhoPhi,    const surfaceScalarField&amp; phi,    const transportModel&amp; transport,    const word&amp; propertiesName)&#123;    // get model name, but do not register the dictionary    // otherwise it is registered in the database twice    const word modelType    (        IOdictionary        (            IOobject            (                IOobject::groupName(propertiesName, U.group()),                U.time().constant(),                U.db(),                IOobject::MUST_READ_IF_MODIFIED,                IOobject::NO_WRITE,                false            )        ).lookup(&quot;simulationType&quot;)    );    Info&lt;&lt; &quot;Selecting turbulence model type &quot; &lt;&lt; modelType &lt;&lt; endl;    typename dictionaryConstructorTable::iterator cstrIter =        dictionaryConstructorTablePtr_-&gt;find(modelType);    if (cstrIter == dictionaryConstructorTablePtr_-&gt;end())    &#123;        FatalErrorInFunction            &lt;&lt; &quot;Unknown TurbulenceModel type &quot;            &lt;&lt; modelType &lt;&lt; nl &lt;&lt; nl            &lt;&lt; &quot;Valid TurbulenceModel types:&quot; &lt;&lt; endl            &lt;&lt; dictionaryConstructorTablePtr_-&gt;sortedToc()            &lt;&lt; exit(FatalError);    &#125;    return autoPtr&lt;TurbulenceModel&gt;    (        cstrIter()(alpha, rho, U, alphaRhoPhi, phi, transport, propertiesName)    );&#125;



这里通过读取 turbulenceProperties 文件，查找关键字 simulationType（只能是 RAS 或 LES ），并据此从定义在 TurbulenceModel 类中 hashTable 中找对应的模型，然后返回的模型（可能是 RAStransportModelIncompressibleTurbulenceModel， RASfluidThermoCompressibleTurbulenceModel， RASsinglePhaseTransportModelPhaseIncompressibleTurbulenceModel， RASphaseModelPhaseCompressibleTurbulenceModel）的 New 函数
template&lt;class BasicTurbulenceModel&gt;Foam::autoPtr&lt;Foam::RASModel&lt;BasicTurbulenceModel&gt; &gt;Foam::RASModel&lt;BasicTurbulenceModel&gt;::New(    const alphaField&amp; alpha,    const rhoField&amp; rho,    const volVectorField&amp; U,    const surfaceScalarField&amp; alphaRhoPhi,    const surfaceScalarField&amp; phi,    const transportModel&amp; transport,    const word&amp; propertiesName)&#123;    // get model name, but do not register the dictionary    // otherwise it is registered in the database twice    const word modelType    (        IOdictionary        (            IOobject            (                IOobject::groupName(propertiesName, U.group()),                U.time().constant(),                U.db(),                IOobject::MUST_READ_IF_MODIFIED,                IOobject::NO_WRITE,                false            )        ).subDict(&quot;RAS&quot;).lookup(&quot;RASModel&quot;)    );    Info&lt;&lt; &quot;Selecting RAS turbulence model &quot; &lt;&lt; modelType &lt;&lt; endl;    typename dictionaryConstructorTable::iterator cstrIter =        dictionaryConstructorTablePtr_-&gt;find(modelType);    if (cstrIter == dictionaryConstructorTablePtr_-&gt;end())    &#123;        FatalErrorInFunction            &lt;&lt; &quot;Unknown RASModel type &quot;            &lt;&lt; modelType &lt;&lt; nl &lt;&lt; nl            &lt;&lt; &quot;Valid RASModel types:&quot; &lt;&lt; endl            &lt;&lt; dictionaryConstructorTablePtr_-&gt;sortedToc()            &lt;&lt; exit(FatalError);    &#125;    return autoPtr&lt;RASModel&gt;    (        cstrIter()(alpha, rho, U, alphaRhoPhi, phi, transport, propertiesName)    );&#125;



这个 New 函数中需要读取 RAS 子字典，从中读取 RASModel 关键字，并据此从定义在 RASModel 类中的 hashTable 中查找到对应的湍流模型，并返回湍流模型的构造函数
 return autoPtr&lt;RASModel&gt;(    cstrIter()(alpha, rho, U, alphaRhoPhi, phi, transport, propertiesName));



